import { postRescueApi } from '../api';
import { useRootStore } from '../../store';
import { RescueStatus, RescuePayload } from '../models';
import { getParticipantIdFromToken } from '../utils';

export async function postRescue(payload: RescuePayload): Promise<boolean> {
  const { rescueActions } = useRootStore.getState();

  try {
    rescueActions.setStatus(RescueStatus.LOADING);

    const participantId = payload.participantId ?? (await getParticipantIdFromToken());

    const finalPayload: RescuePayload = {
      ...payload,
      ...(participantId ? { participantId } : {}),
    };

    const response = await postRescueApi(finalPayload);

    const rawStatus = response?.data?.status ?? response?.data?.data?.status;

    if (!rawStatus) {
      rescueActions.setError('No status in response');
      return false;
    }

    const isSuccess = rawStatus?.message?.toLowerCase() === 'success';

    if (isSuccess) {
      rescueActions.setSuccess(rawStatus);
      return true;
    }

    rescueActions.setError(rawStatus?.message || 'Rescue failed');
    return false;
  } catch {
    rescueActions.setError('Rescue request failed');
    return false;
  }
}

export function clearRescue(): void {
  const { rescueActions } = useRootStore.getState();
  rescueActions.reset();
}

