import { useCallback } from 'react';
import { useShallow } from 'zustand/react/shallow';
import { useRootStore } from '../../store';
import { marketplaceService } from '../services';
import { MARKETPLACE_PARAMS } from '../models';

export const useMarketplace = () => {
  const marketplace = useRootStore(useShallow((state) => state.marketplace));

  const fetchMarketplaceToken = useCallback(async (): Promise<boolean> => {
    const { marketplaceActions } = useRootStore.getState();

    try {
      marketplaceActions.setLoading(true);

      const response = await marketplaceService.getToken(MARKETPLACE_PARAMS);

      if (response.status.codigoRetorno === 0) {
        marketplaceActions.setRedirectURL(response.dados.redirectURL);
        return true;
      } else {
        marketplaceActions.setError(response.status.mensagem || 'Failed to get token');
        return false;
      }
    } catch (error) {
      marketplaceActions.setError('Failed to load marketplace');
      return false;
    }
  }, []);

  const reset = useCallback(() => {
    useRootStore.getState().marketplaceActions.reset();
  }, []);

  return {
    ...marketplace,
    fetchMarketplaceToken,
    reset,
  };
};

