import { useCallback } from 'react';
import { getClientNRC } from '../../hooks/useSelectors';
import { invoiceCashbackPermissionService } from '../services';
import { useRootStore } from '../../store';

export function useInvoiceCashbackPermission() {
  const accountId = getClientNRC();

  const { hasRedeemed, isLoading, isError } = useRootStore(
    (state) => state.invoiceCashbackPermission
  );

  const { setHasRedeemed, setLoading, setError } = useRootStore(
    (state) => state.invoiceCashbackPermissionActions
  );

  const checkHasRedeemed = useCallback(
    async ({
      showLoading = false,
      forceRefresh = false,
    }: { showLoading?: boolean; forceRefresh?: boolean } = {}): Promise<boolean> => {
      if (hasRedeemed !== null && !forceRefresh) {
        return hasRedeemed;
      }

      if (!accountId) {
        throw new Error('Expected accountId to be defined.');
      }

      if (showLoading) {
        setLoading(true);
      }

      try {
        const result = await invoiceCashbackPermissionService.hasRedeemed(accountId);
        setHasRedeemed(result);
        return result;
      } catch {
        setError(true);
        return false;
      }
    },
    [accountId, hasRedeemed, setHasRedeemed, setLoading, setError]
  );

  const markAsRedeemed = useCallback(async (): Promise<boolean> => {
    if (!accountId) {
      return false;
    }

    try {
      await invoiceCashbackPermissionService.markAsRedeemed(accountId);
      setHasRedeemed(true);
      return true;
    } catch {
      return false;
    }
  }, [accountId, setHasRedeemed]);

  return {
    hasRedeemed,
    isLoading,
    isError,
    checkHasRedeemed,
    markAsRedeemed,
  };
}

